class Mahasiswa:
    def __init__(self, nim, nama):
        self.__nim = nim    # private
        self.nama = nama

    def get_nim(self):      # getter
        return self.__nim

class Mahasiswa:
    def info(self):
        return f"[Mahasiswa] {self.nama}"

class MahasiswaS1(Mahasiswa):
    def info(self):             # override
        return f"[S1] {self.nama} | Skripsi: {self.skripsi}"
